import { useState } from "react";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from "../ui/dialog";
import { Button } from "../ui/button";

type ProxyTokenDialogProps = {
  open: boolean;
  token: string;
  agentName: string;
  onClose: () => void;
};

export function ProxyTokenDialog({ open, token, agentName, onClose }: ProxyTokenDialogProps) {
  const [copied, setCopied] = useState(false);

  async function handleCopy() {
    await navigator.clipboard.writeText(token);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  }

  return (
    <Dialog open={open} onOpenChange={(isOpen) => { if (!isOpen) onClose(); }}>
      <DialogContent className="max-w-md">
        <DialogHeader>
          <DialogTitle>Proxy Token for {agentName}</DialogTitle>
        </DialogHeader>
        <div className="flex flex-col gap-3">
          <p className="text-xs text-muted-foreground">
            This token is shown only once. Copy it now and store it securely. It will be used as the <code className="rounded bg-muted px-1">X-Brain-Auth</code> header value for this agent's API requests.
          </p>

